// ── SCHED ─────────────────────────────────────────────────────────────────
function renderSched(){
  var rem=_D.meta.survivorEligibleCount || SURVIVOR_COACHES.length;
  // heat intensity by drop size: 0=green, 4=blue-tinge, 5=amber, 10=orange, 15=red-orange, 20=red
  function heatColor(pct){
    // pct = % of current field being eliminated this round
    if(pct===0)   return {bg:'rgba(52,211,153,0.08)', lbl:'Safe',     lc:'var(--green)'};
    if(pct<5)     return {bg:'rgba(96,165,250,0.08)', lbl:'Low',      lc:'var(--blue)'};
    if(pct<10)    return {bg:'rgba(240,180,41,0.08)', lbl:'Moderate', lc:'var(--accent)'};
    if(pct<20)    return {bg:'rgba(251,146,60,0.12)', lbl:'Heavy',    lc:'#fb923c'};
    if(pct<35)    return {bg:'rgba(248,113,113,0.12)',lbl:'Danger',   lc:'var(--red)'};
    return               {bg:'rgba(220,38,38,0.18)',  lbl:'Brutal',   lc:'#ef4444'};
  }
  // Pre-calculate remaining before each round so pct uses the right denominator
  var remBefore=_D.meta.survivorEligibleCount || SURVIVOR_COACHES.length; rem=remBefore;
  document.getElementById('sgrid').innerHTML=DROP.map(function(item){
    var before = remBefore;
    rem=Math.max(0,rem-item.d);
    remBefore = rem;
    var pct = before > 0 ? Math.round((item.d/before)*100) : 0;
    var cls=item.r===CUR?'cur':item.r<CUR?'past':'';
    var h=heatColor(pct);
    var tooltip='R'+item.r+(item.d>0?': -'+item.d+' eliminated ('+pct+'% of field)':': no cuts');
    var extraClick;
    if(item.r===27){
      extraClick=' onclick="document.getElementById(\'bunker-modal\').style.display=\'flex\'"';
    } else if(item.d>0){
      extraClick=' onclick="showElimForRound('+item.r+')"';
    } else {
      extraClick='';
    }
    return '<div class="scel '+cls+'"'+extraClick+' data-round="'+item.r+'" title="'+tooltip+'" style="background:'+h.bg+';'+(item.d>0||item.r===27?'cursor:pointer':'')+'">'
      +'<div class="scr">R'+item.r+'</div>'
      +'<div class="scd '+(item.d===0?'z':'')+'" style="color:'+h.lc+'">'+( item.d===0?'—':'-'+item.d)+'</div>'
      +'<div class="scre">'+rem+' left</div>'
      +'<div style="font-size:.6rem;font-weight:700;color:'+h.lc+'">'+(pct>0?pct+'%':'')+'</div>'
      +'</div>';
  }).join('');
}

// ── SHOW ELIMINATED FOR ROUND ─────────────────────────────────────────────
var _elimOpenRound=null;
function showElimForRound(r){
  var popup=document.getElementById('elim-popup');
  if(!popup) return;
  // Toggle off if same round clicked again
  if(_elimOpenRound===r){
    popup.style.display='none';
    _elimOpenRound=null;
    // Remove active highlight
    document.querySelectorAll('.scel').forEach(function(el){el.classList.remove('elim-active');});
    return;
  }
  _elimOpenRound=r;
  var coaches=(_D.eliminatedByRound||{})[String(r)]||[];
  // Highlight the clicked cell
  document.querySelectorAll('.scel').forEach(function(el){el.classList.remove('elim-active');});
  var cells=document.querySelectorAll('.scel');
  cells.forEach(function(el){
    if(el.getAttribute('onclick')==='showElimForRound('+r+')') el.classList.add('elim-active');
  });
  if(coaches.length===0){
    popup.style.display='none';
    _elimOpenRound=null;
    return;
  }
  var rows=coaches.map(function(e,i){
    return '<tr><td style="padding:.3rem .6rem;font-size:.8rem;color:var(--muted);width:28px">'+(i+1)+'</td>'
      +'<td style="padding:.3rem .6rem;font-size:.85rem;font-weight:600">'+esc(e.coach)+'</td>'
      +'<td style="padding:.3rem .6rem;font-size:.8rem;color:var(--muted)">'+esc(e.team)+'</td>'
      +'<td style="padding:.3rem .6rem;font-size:.85rem;color:var(--red);font-weight:700;text-align:right">'+e.score+'</td>'
      +'</tr>';
  }).join('');
  popup.innerHTML='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.6rem">'
    +'<span style="font-size:.85rem;font-weight:700;color:var(--red)">✗ Eliminated after Round '+r+' — '+coaches.length+' coaches</span>'
    +'<button onclick="showElimForRound('+r+')" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:1rem;line-height:1">✕</button>'
    +'</div>'
    +'<div class="tw-scroll"><table style="width:100%;border-collapse:collapse">'
    +'<thead><tr>'
    +'<th style="padding:.3rem .6rem;font-size:.7rem;color:var(--muted);text-align:left;text-transform:uppercase;letter-spacing:.08em">#</th>'
    +'<th style="padding:.3rem .6rem;font-size:.7rem;color:var(--muted);text-align:left;text-transform:uppercase;letter-spacing:.08em">Coach</th>'
    +'<th style="padding:.3rem .6rem;font-size:.7rem;color:var(--muted);text-align:left;text-transform:uppercase;letter-spacing:.08em">Team</th>'
    +'<th style="padding:.3rem .6rem;font-size:.7rem;color:var(--muted);text-align:right;text-transform:uppercase;letter-spacing:.08em">R'+r+' Score</th>'
    +'</tr></thead>'
    +'<tbody>'+rows+'</tbody>'
    +'</table></div>';
  popup.style.display='block';
}
