var plList = [];
function buildPlList(){
  plList = Object.keys(PLAYERS).map(function(pid){
    return Object.assign({pid:pid}, PLAYERS[pid]);
  });
}
// Compute Top-N ownership counts (cached by N value)
var _topNCache={N:-1,counts:{}};
function getTopNOwnership(n){
  if(_topNCache.N===n) return _topNCache.counts;
  var counts={};
  COACHES.forEach(function(c){
    if(c.rank>n) return;
    (c.players||[]).forEach(function(pid){ counts[pid]=(counts[pid]||0)+1; });
  });
  _topNCache={N:n,counts:counts};
  return counts;
}

function fPlayers(){
  var q=document.getElementById('plfi').value.toLowerCase().trim();
  var sortEl=document.getElementById('plsort');
  var sort=sortEl?sortEl.value:'ownedDesc';
  var topNEl=document.getElementById('pltopn');
  var N=topNEl?Math.min(300,Math.max(1,parseInt(topNEl.value)||100)):100;
  var hdr=document.getElementById('topn-header');
  if(hdr) hdr.textContent='Top '+N;
  var topNCounts=getTopNOwnership(N);
  var filtered=plList.map(function(p){
    var topNOwned=(topNCounts[p.pid]||0);
    var topNPct=Math.round(topNOwned/N*1000)/10;
    return Object.assign({},p,{topNOwned:topNOwned,topNPct:topNPct});
  }).filter(function(p){
    return !q||p.name.toLowerCase().indexOf(q)>=0;
  });
  filtered.sort(function(a,b){
    if(sort==='ownedAsc')  return a.ownedPct-b.ownedPct;
    if(sort==='topN')      return b.topNPct-a.topNPct;
    if(sort==='cost')      return b.cost-a.cost;
    if(sort==='tradedIn')  return b.tradedIn-a.tradedIn;
    if(sort==='tradedOut') return b.tradedOut-a.tradedOut;
    return b.ownedPct-a.ownedPct;
  });
  var ctEl=document.getElementById('plct');
  if(ctEl) ctEl.textContent=filtered.length+' players';
  var rows='';
  filtered.forEach(function(p,i){
    var col=p.ownedPct>=90?'var(--red)':p.ownedPct>=70?'var(--accent)':p.ownedPct>=40?'var(--text)':'var(--green)';
    var colN=p.topNPct>=90?'var(--red)':p.topNPct>=70?'var(--accent)':p.topNPct>=40?'var(--text)':'var(--green)';
    var bar=Math.max(2,Math.round(p.ownedPct));
    rows+='<tr onclick="showPlayerCard(\''+p.pid+'\')" style="cursor:pointer;">'
      +'<td class="trk">'+(i+1)+'</td>'
      +'<td style="font-weight:600">'+esc(p.name)+'</td>'
      +'<td style="font-family:Bebas Neue,sans-serif;color:var(--muted)">$'+(p.cost/1000).toFixed(0)+'K</td>'
      +'<td><div style="display:flex;align-items:center;gap:.5rem;">'
        +'<div style="width:56px;height:6px;background:var(--border);border-radius:3px;flex-shrink:0;overflow:hidden;"><div style="width:'+bar+'%;height:100%;background:'+col+';border-radius:3px;"></div></div>'
        +'<span style="font-weight:700;color:'+col+'">'+p.ownedPct+'%</span>'
      +'</div></td>'
      +'<td style="font-size:.82rem;font-weight:700;color:'+colN+';background:rgba(240,180,41,.06);border-left:2px solid rgba(240,180,41,.2);border-right:2px solid rgba(240,180,41,.2);">'+p.topNPct+'%</td>'
      +'<td style="color:var(--green);font-weight:700">'+(p.tradedIn>0?'+'+p.tradedIn:'—')+'</td>'
      +'<td style="font-size:.8rem;color:var(--green)">'+(p.tradedInPct>0?p.tradedInPct+'%':'—')+'</td>'
      +'<td style="font-size:.8rem;color:var(--accent)">'+(p.eligInPct>0?p.eligInPct+'%':'—')+'</td>'
      +'<td style="color:var(--red);font-weight:700">'+(p.tradedOut>0?'-'+p.tradedOut:'—')+'</td>'
      +'<td style="font-size:.8rem;color:var(--red)">'+(p.tradedOutPct>0?p.tradedOutPct+'%':'—')+'</td>'
      +'<td style="font-size:.8rem;color:var(--accent)">'+(p.eligOutPct>0?p.eligOutPct+'%':'—')+'</td>'
      +'</tr>';
  });
  var plb=document.getElementById('plb');
  if(plb) plb.innerHTML=rows||'<tr><td colspan="11" style="text-align:center;padding:2rem;color:var(--muted)">No players found.</td></tr>';

  // Mobile card list
  var cards='';
  filtered.forEach(function(p,i){
    var col=p.ownedPct>=90?'var(--red)':p.ownedPct>=70?'var(--accent)':p.ownedPct>=40?'var(--text)':'var(--green)';
    var colN=p.topNPct>=90?'var(--red)':p.topNPct>=70?'var(--accent)':p.topNPct>=40?'var(--text)':'var(--green)';
    var bar=Math.max(2,Math.round(p.ownedPct));
    cards+='<div onclick="showPlayerCard(\''+p.pid+'\')" style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:.75rem 1rem;margin-bottom:.5rem;cursor:pointer;">'
      // Player name + price row
      +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem;">'
        +'<div style="font-weight:700;font-size:.95rem">'+esc(p.name)+'</div>'
        +'<div style="font-family:Bebas Neue,sans-serif;color:var(--muted);font-size:.9rem">$'+(p.cost/1000).toFixed(0)+'K</div>'
      +'</div>'
      // Ownership bar + % row
      +'<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.5rem;">'
        +'<div style="flex:1;height:6px;background:var(--border);border-radius:3px;overflow:hidden;"><div style="width:'+bar+'%;height:100%;background:'+col+';border-radius:3px;"></div></div>'
        +'<span style="font-weight:700;color:'+col+';font-size:.85rem;min-width:38px">'+p.ownedPct+'%</span>'
        +'<span style="font-size:.75rem;color:var(--muted)">all 300</span>'
        +'<span style="font-size:.82rem;font-weight:700;color:'+colN+';background:rgba(240,180,41,.08);border:1px solid rgba(240,180,41,.2);border-radius:4px;padding:.1rem .35rem;">'+p.topNPct+'% top '+N+'</span>'
      +'</div>'
      // Trades row
      +'<div style="display:flex;gap:.5rem;flex-wrap:wrap;">'
        +(p.tradedIn>0
          ?'<span style="font-size:.75rem;background:rgba(52,211,153,.1);border:1px solid rgba(52,211,153,.25);border-radius:5px;padding:.15rem .5rem;color:var(--green)">+'+p.tradedIn+' in'+(p.tradedInPct?' ('+p.tradedInPct+'%'+( p.eligInPct?' / '+p.eligInPct+'% elig':'')+')'  :'')+'</span>'
          :'')
        +(p.tradedOut>0
          ?'<span style="font-size:.75rem;background:rgba(248,113,113,.1);border:1px solid rgba(248,113,113,.25);border-radius:5px;padding:.15rem .5rem;color:var(--red)">-'+p.tradedOut+' out'+(p.tradedOutPct?' ('+p.tradedOutPct+'%'+(p.eligOutPct?' / '+p.eligOutPct+'% elig':'')+')'  :'')+'</span>'
          :'')
        +(!p.tradedIn&&!p.tradedOut?'<span style="font-size:.75rem;color:var(--muted)">No trades this round</span>':'')
      +'</div>'
      +'</div>';
  });
  var plCards=document.getElementById('pl-card-list');
  if(plCards) plCards.innerHTML=cards||'<p style="text-align:center;padding:2rem;color:var(--muted);font-size:.875rem">No players found.</p>';
}
