function renderTradeSummary(){
  var ovRndEl=document.getElementById('ov-trade-rnd');
  if(ovRndEl&&CUR>1) ovRndEl.textContent='R'+(CUR-1)+' → R'+CUR;

  function tradeRow(item,isIn){
    var col=isIn?'var(--green)':'var(--red)';
    var sign=isIn?'+':'-';
    var pcts='';
    if(item.totalPct){
      pcts='<div style="font-size:.7rem;color:var(--muted);margin-top:.1rem">'
        +'<span style="color:'+col+';font-weight:600">'+item.totalPct+'%</span> of field'
        +(item.eligPct?' · <span style="color:var(--accent);font-weight:600">'+item.eligPct+'%</span> of eligible':'')
        +'</div>';
    }
    return '<div style="display:flex;align-items:center;justify-content:space-between;padding:.45rem 1rem;border-bottom:1px solid var(--border);">'
      +'<div>'
        +'<div style="font-size:.85rem;font-weight:600">'+esc(item.name)+'</div>'
        +pcts
      +'</div>'
      +'<span style="font-family:Bebas Neue,sans-serif;font-size:1.1rem;color:'+col+';flex-shrink:0;margin-left:.5rem">'+sign+item.count+'</span>'
      +'</div>';
  }

  var ti=TRADE_SUMMARY['in']||[], to=TRADE_SUMMARY['out']||[];
  var ovIn=document.getElementById('ov-traded-in');
  if(ovIn) ovIn.innerHTML=ti.slice(0,5).map(function(x){return tradeRow(x,true);}).join('');
  var ovOut=document.getElementById('ov-traded-out');
  if(ovOut) ovOut.innerHTML=to.slice(0,5).map(function(x){return tradeRow(x,false);}).join('');
  var plIn=document.getElementById('pl-traded-in');
  if(plIn) plIn.innerHTML=ti.map(function(x){return tradeRow(x,true);}).join('');
  var plOut=document.getElementById('pl-traded-out');
  if(plOut) plOut.innerHTML=to.map(function(x){return tradeRow(x,false);}).join('');
}


function dPager(id,total,cur,cb){
  var el=document.getElementById(id);
  if(total<=1){el.innerHTML='';return;}
  var h='';
  if(cur>1)h+='<button class="pg" onclick="('+cb+')('+(cur-1)+')">‹</button>';
  for(var p=1;p<=total;p++){
    if(p===1||p===total||Math.abs(p-cur)<=1) h+='<button class="pg '+(p===cur?'on':'')+'" onclick="('+cb+')('+p+')">'+p+'</button>';
    else if(Math.abs(p-cur)===2) h+='<span class="pgd">…</span>';
  }
  if(cur<total)h+='<button class="pg" onclick="('+cb+')('+(cur+1)+')">›</button>';
  el.innerHTML=h;
}


// ── TIER BOUNDARY ─────────────────────────────────────────────────────────
function tierBoundaryHtml(rank, c){
  var ROUNDS_LEFT = 8 - CUR;
  var phase = CUR <= 8 ? 1 : CUR <= 18 ? 2 : 3;
  if(phase !== 1) return '';

  var t = getTier(rank);
  var html = '<div class="cvsec"><div class="cvsect">⚠️ Tier Boundary Alert</div>';

  // Helper: get total score for coach at a given rank
  function scoreAt(r){
    var cx = COACHES.find(function(x){return x.rank===r;});
    return cx ? (cx.total||cx.r1||0) : 0;
  }
  var myScore = c.total || c.r1 || 0;

  if(t === 1){
    // Already in Tier 1 — show buffer (places inside the cut)
    var bufferPlaces = T1 - rank;
    var t1cutScore = scoreAt(T1);
    var ptsBuffer = myScore - t1cutScore;
    var barW1 = Math.min(95, Math.max(5, Math.round((bufferPlaces/T1)*100)));
    var bufLabel = bufferPlaces === 0 ? '⚠️ On the cut' : ('✓ '+bufferPlaces+' place'+(bufferPlaces!==1?'s':'')+' inside');
    var bufStyle = bufferPlaces === 0 ? 'background:rgba(240,180,41,.15);color:var(--accent);border-color:rgba(240,180,41,.3)' : 'background:rgba(52,211,153,.15);color:var(--green);border-color:rgba(52,211,153,.3)';
    var pillCol = bufferPlaces === 0 ? 'var(--accent)' : 'var(--green)';
    html += '<div class="tier-boundary">'
      +'<div class="tb-header"><span class="tb-title">Tier 1 — Premiership</span><span class="badge bt1" style="'+bufStyle+'">'+bufLabel+'</span></div>'
      +'<div class="tb-bar-wrap"><div class="tb-bar" style="width:'+barW1+'%;background:linear-gradient(90deg,var(--green),rgba(52,211,153,.3))"></div></div>'
      +'<div class="tb-stats">'
      +(bufferPlaces===0
        ? '<span class="tb-pill" style="color:var(--accent)"><strong>Right on the T1 boundary</strong></span>'
        : '<span class="tb-pill" style="color:'+pillCol+'"><strong>'+bufferPlaces+' place'+(bufferPlaces!==1?'s':'')+' buffer</strong></span>')
      +'<span class="tb-pill" style="color:'+pillCol+'"><strong>+'+ptsBuffer+' pts over the cut</strong></span>'
      +'<span class="tb-pill" style="color:var(--muted)">'+ROUNDS_LEFT+' round'+(ROUNDS_LEFT!==1?'s':'')+' left</span>'
      +'</div>'
      +'</div>';

  } else if(t === 2){
    var toT1 = rank - T1;
    var t1cutScore = scoreAt(T1);
    var ptsToT1 = t1cutScore - myScore;
    var barW2 = Math.min(95, Math.max(5, 100 - Math.round((toT1/100)*100)));
    html += '<div class="tier-boundary">'
      +'<div class="tb-header"><span class="tb-title">Tier 1 — Premiership</span><span class="badge bt1">'+toT1+' place'+(toT1!==1?'s':'')+' away ↑</span></div>'
      +'<div class="tb-bar-wrap"><div class="tb-bar" style="width:'+barW2+'%;background:linear-gradient(90deg,var(--t1),rgba(240,180,41,.3))"></div></div>'
      +'<div class="tb-stats">'
      +'<span class="tb-pill" style="color:var(--accent)"><strong>'+toT1+' place'+(toT1!==1?'s':'')+' needed</strong></span>'
      +'<span class="tb-pill" style="color:var(--accent)"><strong>'+ptsToT1+' pt'+(ptsToT1!==1?'s':'')+' needed</strong></span>'
      +'<span class="tb-pill" style="color:var(--muted)">'+ROUNDS_LEFT+' round'+(ROUNDS_LEFT!==1?'s':'')+' left</span>'
      +'</div>'
      +'</div>';

  } else {
    // Tier 3 — show distance to Tier 2 only
    var toT2climb = rank - T2;
    var t2topScore = scoreAt(T2);
    var ptsToT2 = t2topScore - myScore;
    html += '<div class="tier-boundary">'
      +'<div class="tb-header"><span class="tb-title">Tier 2 — Championship</span><span class="badge bt2">'+toT2climb+' place'+(toT2climb!==1?'s':'')+' away ↑</span></div>'
      +'<div class="tb-bar-wrap"><div class="tb-bar" style="width:'+Math.max(5,100-Math.round((toT2climb/100)*100))+'%;background:linear-gradient(90deg,var(--t2),rgba(96,165,250,.3))"></div></div>'
      +'<div class="tb-stats">'
      +'<span class="tb-pill" style="color:var(--blue)"><strong>'+toT2climb+' place'+(toT2climb!==1?'s':'')+' needed</strong></span>'
      +'<span class="tb-pill" style="color:var(--blue)"><strong>'+ptsToT2+' pt'+(ptsToT2!==1?'s':'')+' needed</strong></span>'
      +'<span class="tb-pill" style="color:var(--muted)">'+ROUNDS_LEFT+' round'+(ROUNDS_LEFT!==1?'s':'')+' left</span>'
      +'</div>'
      +'</div>';
  }

  html += '</div>';
  return html;
}

// ── SPARKLINE ─────────────────────────────────────────────────────────────
// ── POD (Point of Difference) ────────────────────────────────────────────────
function podHtml(c){
  if(!c.players||!c.players.length) return '';
  var totalCoaches=COACHES.length;
  // Get players sorted by lowest ownership (most POD first)
  var withOwnership=c.players.map(function(pid){
    var p=PLAYERS[pid];
    if(!p) return null;
    return {pid:pid,name:p.name,cost:p.cost,owned:p.owned,ownedPct:p.ownedPct};
  }).filter(Boolean).sort(function(a,b){return a.ownedPct-b.ownedPct});
  var pods=withOwnership.slice(0,3);
  if(!pods.length) return '';

  var html='<div class="cvsec"><div class="cvsect">🎯 Points of Difference</div>';
  html+='<p style="font-size:.8rem;color:var(--muted);margin-bottom:.85rem;line-height:1.5">Your 3 most unique players — lowest ownership among JBFA coaches.</p>';
  html+='<div style="display:flex;flex-direction:column;gap:.5rem;">';
  pods.forEach(function(p,i){
    var col=p.ownedPct<=10?'var(--green)':p.ownedPct<=25?'var(--accent)':'var(--blue)';
    var bar=Math.max(3,Math.round(p.ownedPct));
    html+='<div style="background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:.6rem .85rem;display:flex;align-items:center;gap:.85rem;">'
      +'<div style="font-family:Bebas Neue,sans-serif;font-size:1.3rem;color:'+col+';min-width:28px;text-align:center">'+(i+1)+'</div>'
      +'<div style="flex:1;min-width:0;">'
        +'<div style="font-weight:600;font-size:.88rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+esc(p.name)+'</div>'
        +'<div style="display:flex;align-items:center;gap:.5rem;margin-top:.25rem;">'
          +'<div style="flex:1;max-width:100px;height:5px;background:var(--border);border-radius:3px;overflow:hidden;"><div style="width:'+bar+'%;height:100%;background:'+col+';border-radius:3px;"></div></div>'
          +'<span style="font-size:.72rem;color:'+col+';font-weight:700">'+p.ownedPct+'%</span>'
          +'<span style="font-size:.72rem;color:var(--muted)">'+(p.owned)+' / '+totalCoaches+' coaches</span>'
        +'</div>'
      +'</div>'
      +'<div style="font-size:.78rem;color:var(--muted);text-align:right;flex-shrink:0">$'+(p.cost/1000).toFixed(0)+'K</div>'
      +'</div>';
  });
  html+='</div></div>';
  return html;
}


// ── RANK HISTORY ─────────────────────────────────────────────────────────────
function rankHistoryHtml(c){
  var rh=c.rankHistory||{};
  var rounds=Object.keys(rh).sort(function(a,b){return parseInt(a.replace('r',''))-parseInt(b.replace('r',''));});
  var platformRanks=c.platformRanks||{};
  var prRounds=Object.keys(platformRanks).sort(function(a,b){return parseInt(a.replace('r',''))-parseInt(b.replace('r',''));});
  if(rounds.length===0&&prRounds.length===0) return '';
  var total=COACHES.length;
  var out='';

  // ── Section 1: JBFA Rank History ──
  if(rounds.length>0){
    out+='<div class="cvsec">';
    out+='<div class="cvsect">📈 JBFA Rank History</div>';
    out+='<div style="font-size:.75rem;color:var(--muted);margin-top:-.4rem;margin-bottom:.75rem">Your standing among the JBFA coaches, cumulative after each round</div>';
    out+='<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
    rounds.forEach(function(rk,i){
      var rNum=parseInt(rk.replace('r',''));
      var rankVal=rh[rk];
      var col=rankVal<=Math.ceil(total*0.10)?'var(--green)':rankVal<=Math.ceil(total*0.33)?'var(--accent)':rankVal<=Math.ceil(total*0.67)?'var(--blue)':'var(--muted)';
      var prevRk=i>0?rh[rounds[i-1]]:null;
      var mvt='';
      if(prevRk!==null){
        var diff=prevRk-rankVal;
        if(diff>0) mvt='<span style="font-size:.65rem;color:var(--green)">&#9650;'+diff+'</span>';
        else if(diff<0) mvt='<span style="font-size:.65rem;color:var(--red)">&#9660;'+Math.abs(diff)+'</span>';
        else mvt='<span style="font-size:.65rem;color:var(--muted)">&#8212;</span>';
      }
      var isCur=rNum===CUR;
      out+='<div style="background:'+(isCur?'rgba(240,180,41,.1)':'var(--surface2)')+';border:1px solid '+(isCur?'rgba(240,180,41,.3)':'var(--border)')+';border-radius:8px;padding:.5rem .75rem;min-width:76px;text-align:center;">'
        +'<div style="font-size:.65rem;text-transform:uppercase;letter-spacing:.08em;color:var(--muted);margin-bottom:.15rem">R'+rNum+(isCur?' &#9668;':'')+' </div>'
        +'<div style="font-family:Bebas Neue,sans-serif;font-size:1.5rem;color:'+col+';letter-spacing:.04em;line-height:1">#'+rankVal+'</div>'
        +(mvt?'<div style="margin-top:.2rem">'+mvt+'</div>':'')
        +'</div>';
    });
    out+='</div>';
    out+='</div>';
  }

  // ── Section 2: NRL Fantasy Platform Rank chart ──
  if(prRounds.length>=1){
    var prVals=prRounds.map(function(rk){return platformRanks[rk];});
    var prMax=Math.max.apply(null,prVals);
    var prMin=Math.min.apply(null,prVals);
    var prPad=Math.max(500,Math.round((prMax-prMin)*0.3));
    var lo=Math.max(1,prMin-prPad),hi=prMax+prPad;
    var W=320,H=80,padL=8,padR=8,padT=20,padB=20;
    var chartW=W-padL-padR,chartH=H-padT-padB;
    function xPos(i){return padL+Math.round(i/(prRounds.length-1||1)*chartW);}
    function yPos(v){return padT+Math.round(((v-lo)/(hi-lo||1))*chartH);}
    var pts=prVals.map(function(v,i){return xPos(i)+','+yPos(v);});
    var linePath='M'+pts.join(' L');
    var fillPath='M'+xPos(0)+','+(padT+chartH)+' L'+pts.join(' L')+' L'+xPos(prRounds.length-1)+','+(padT+chartH)+' Z';

    out+='<div class="cvsec">';
    out+='<div class="cvsect">🌐 NRL Fantasy Platform Rank</div>';
    out+='<div style="font-size:.75rem;color:var(--muted);margin-top:-.4rem;margin-bottom:.85rem">Your rank across all NRL Fantasy users nationwide — not just JBFA. Lower = better.</div>';
    out+='<svg viewBox="0 0 '+W+' '+H+'" style="width:100%;max-width:420px;display:block;overflow:visible">';
    out+='<path d="'+fillPath+'" fill="rgba(96,165,250,0.08)"/>';
    out+='<path d="'+linePath+'" fill="none" stroke="var(--blue)" stroke-width="2" stroke-linejoin="round"/>';
    prRounds.forEach(function(rk,i){
      var rNum=parseInt(rk.replace('r',''));
      var v=prVals[i];
      var x=xPos(i),y=yPos(v);
      var isCur=rNum===CUR;
      var col=isCur?'var(--accent)':'var(--blue)';
      out+='<circle cx="'+x+'" cy="'+y+'" r="'+(isCur?4:3)+'" fill="'+col+'"/>';
      var labelY=Math.max(12,y-6);
      out+='<text x="'+x+'" y="'+labelY+'" text-anchor="middle" font-size="9" fill="'+col+'" font-family="DM Sans,sans-serif" font-weight="'+(isCur?'700':'400')+'">#'+v.toLocaleString()+'</text>';
      out+='<text x="'+x+'" y="'+(padT+chartH+12)+'" text-anchor="middle" font-size="8" fill="var(--muted)" font-family="DM Sans,sans-serif">R'+rNum+'</text>';
    });
    out+='</svg>';
    out+='</div>';
  }

  return out;
}

function sparklineHtml(c){
  // Round averages from JSON data
  var ROUND_AVGS = ROUND_AVGS_FROM_DATA||{1: 926, 2: 1034};
  var scores = [];
  if(c.r1) scores.push({r:1, s:c.r1, avg: ROUND_AVGS[1]||926});
  if(c.r2) scores.push({r:2, s:c.r2, avg: ROUND_AVGS[2]||1034});
  if(c.r3) scores.push({r:3, s:c.r3, avg: ROUND_AVGS[3]||0});
  if(c.r4) scores.push({r:4, s:c.r4, avg: ROUND_AVGS[4]||0});
  if(c.r5) scores.push({r:5, s:c.r5, avg: ROUND_AVGS[5]||0});
  if(c.r6) scores.push({r:6, s:c.r6, avg: ROUND_AVGS[6]||0});
  if(c.r7) scores.push({r:7, s:c.r7, avg: ROUND_AVGS[7]||0});
  if(c.r8) scores.push({r:8, s:c.r8, avg: ROUND_AVGS[8]||0});

  var html = '<div class="cvsec"><div class="cvsect">Score Trend</div><div style="font-size:.75rem;color:var(--muted);margin-top:-.4rem;margin-bottom:.75rem">vs JBFA field average each round</div>';

  if(scores.length === 0){
    html += '<div class="spark-one"><span style="color:var(--muted)">No scores yet.</span></div></div>';
    return html;
  }

  // Score boxes: one per round, coloured green/red vs that round's avg
  html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;margin-bottom:.75rem;">';
  scores.forEach(function(item){
    var diff = item.avg ? item.s - item.avg : 0;
    var isGreen = diff >= 0;
    var color = isGreen ? 'var(--green)' : 'var(--red)';
    var bgColor = isGreen ? 'rgba(52,211,153,.1)' : 'rgba(248,113,113,.1)';
    var borderColor = isGreen ? 'rgba(52,211,153,.3)' : 'rgba(248,113,113,.3)';
    var sign = isGreen ? '+' : '';
    html += '<div style="background:'+bgColor+';border:1px solid '+borderColor+';border-radius:8px;padding:.5rem .75rem;min-width:80px;text-align:center;">'
      + '<div style="font-size:.65rem;text-transform:uppercase;letter-spacing:.08em;color:var(--muted);margin-bottom:.2rem">R'+item.r+'</div>'
      + '<div style="font-family:Bebas Neue,sans-serif;font-size:1.4rem;color:'+color+';letter-spacing:.04em;line-height:1">'+item.s+'</div>'
      + (item.avg ? '<div style="font-size:.7rem;color:'+color+';margin-top:.15rem">'+sign+diff+' vs JBFA avg</div>' : '')
      + '</div>';
  });
  html += '</div>';
  html += '</div>';
  return html;
}


