    if(p.tradedOut>0) tradeHtml+='<div style="background:rgba(248,113,113,.1);border:1px solid rgba(248,113,113,.25);border-radius:8px;padding:.5rem .85rem;text-align:center;flex:1;min-width:90px;">'
      +'<div style="font-family:Bebas Neue,sans-serif;font-size:1.5rem;color:var(--red)">-'+p.tradedOut+'</div>'
      +'<div style="font-size:.7rem;color:var(--muted);text-transform:uppercase;letter-spacing:.08em">Traded Out</div>'
      +(p.tradedOutPct?'<div style="font-size:.75rem;color:var(--red);font-weight:600">'+p.tradedOutPct+'% of field</div>':'')+'</div>';
