// ── SCORE DISTRIBUTION ───────────────────────────────────────────────────
function buildScoreBins(scores) {
  if (!scores.length) return [];
  var min = Math.min.apply(null, scores);
  var max = Math.max.apply(null, scores);
  var BIN = 50;
  var lo = Math.floor(min / BIN) * BIN;
  var hi = Math.ceil(max / BIN) * BIN;
  var bins = [];
  for (var s = lo; s < hi; s += BIN) {
    bins.push({ lo: s, hi: s + BIN, count: 0 });
  }
  for (var i = 0; i < scores.length; i++) {
    var idx = Math.floor((scores[i] - lo) / BIN);
    if (idx >= 0 && idx < bins.length) bins[idx].count++;
  }
  return bins;
}

function renderDistributionChart(bins, container) {
  if (!bins.length) { container.innerHTML = '<p style="color:var(--muted);font-size:.875rem;padding:1rem 0">No data for this round.</p>'; return; }
  var maxCount = Math.max.apply(null, bins.map(function(b){return b.count;}));
  var html = '';
  for (var i = 0; i < bins.length; i++) {
    var b = bins[i];
    var pct = maxCount > 0 ? Math.round((b.count / maxCount) * 100) : 0;
    var isTallest = b.count === maxCount && b.count > 0;
    var barColor = isTallest ? 'var(--accent)' : 'rgba(96,165,250,.55)';
    html += '<div class="sd-bar-row">'
      + '<div class="sd-label">' + b.lo + '–' + (b.hi - 1) + '</div>'
      + '<div class="sd-bar-wrap"><div class="sd-bar" style="width:' + pct + '%;background:' + barColor + ';border-radius:4px;"></div></div>'
      + '<div class="sd-count">' + (b.count > 0 ? b.count : '') + '</div>'
      + '</div>';
  }
  container.innerHTML = html;
}

function renderScoreDistribution(round) {
  var key = 'r' + round;
  var scores = [];
  for (var i = 0; i < COACHES.length; i++) {
    var s = COACHES[i].scores && COACHES[i].scores[key];
    if (s != null && s > 0) scores.push(s);
  }
  var container = document.getElementById('score-distribution');
  var summary = document.getElementById('sd-summary');
  if (!container) return;
  if (!scores.length) {
    summary.textContent = '';
    container.innerHTML = '<p style="color:var(--muted);font-size:.875rem;padding:1rem 0">No score data for Round ' + round + ' yet.</p>';
    return;
  }
  var avg = Math.round(scores.reduce(function(a,b){return a+b;},0) / scores.length);
  var top = Math.max.apply(null, scores);
  summary.innerHTML = '<strong style="color:var(--text)">Avg: ' + avg.toLocaleString() + '</strong> &nbsp;·&nbsp; <strong style="color:var(--accent)">Top: ' + top.toLocaleString() + '</strong> &nbsp;·&nbsp; <span style="color:var(--muted)">' + scores.length + ' coaches</span>';
  var bins = buildScoreBins(scores);
  renderDistributionChart(bins, container);
}

