// ── PRICE PREDICTOR INIT ─────────────────────────────────────────────────
// Called once after _initApp so PLAYERS and BE model data are available.
function _initPricePredictor(beModel) {

  // Show/hide the calculator vs coming-soon based on the feature flag
  document.getElementById('pp-coming-soon').style.display  = ENABLE_PRICE_PREDICTOR ? 'none'  : '';
  document.getElementById('pp-calculator').style.display   = ENABLE_PRICE_PREDICTOR ? ''      : 'none';

  if (!ENABLE_PRICE_PREDICTOR) return;

  // ── Validated BE Model — 5-Game Rolling Window ───────────────────────
  //
  //  Confirmed against NRL Fantasy Coach API across 28 players × 3 rounds.
  //
  //  CURRENT-ROUND BE: taken directly from player.breakEven (API-sourced).
  //  This is exact — the platform publishes it. No formula needed.
  //
  //  CHAINED ROUNDS BE (R+2, R+3): computed from rolling window:
  //    W = min(gamesInWindow + 1, 5)
  //    BE = round(W × price / K) − sum(last (W−1) scores in window)
  //
  //  PPP = $1,000/pt  |  K = 13,000  |  window = 5 games
  //
  //  Accuracy: R+1 ≤$3k (API-anchored), R+2 ~$5k avg, R+3 ~$10k avg.

  var K    = (beModel && beModel.kMagic)  || 13000;
  var PPP  = (beModel && beModel.ppp)     || 1000;
  var CUR_ROUND = (beModel && beModel.currentRound) || (typeof CUR !== 'undefined' ? CUR : 3);

  // Compute chained BE given rounded price + rolling score window (oldest-first array).
  // gamesInWindow = number of scores already in the window array.
  function chainBE(price, window) {
    var n = window.length;             // scores already played in the window
    var W = Math.min(n + 1, 5);      // window size for the upcoming game
    var nPrev = W - 1;               // how many previous scores to subtract
    var prevSum = 0;
    for (var i = Math.max(0, n - nPrev); i < n; i++) prevSum += window[i];
    return Math.round(W * price / K) - prevSum;
  }

  // Project next rounded price from current price + score + BE.
  function projectPrice(price, score, be) {
    return Math.round((price + PPP * (score - be)) / 1000) * 1000;
  }

  function fmt$(v) { return '$' + (v/1000).toFixed(0) + 'k'; }

  // ── State ──────────────────────────────────────────────────────────────
  var ppSelectedPid = null;

  // ── Build player list for search ──────────────────────────────────────
  // orderedScores = scores oldest-first [s1, s2, s3, ...] from data.json
  var ppPlayerList = [];
  Object.keys(PLAYERS).forEach(function(pid) {
    var p = PLAYERS[pid];
    if (p && p.name && p.startPrice) {
      ppPlayerList.push({
        pid:           pid,
        name:          p.name,
        cost:          p.cost || p.startPrice,
        startPrice:    p.startPrice,
        gamesPlayed:   p.gamesPlayed || 0,
        scores:        p.scores || {},
        priceHistory:  p.priceHistory || [],
        // API-sourced BE for the current round — always exact
        breakEven:     p.breakEven,
        // Scores oldest-first: used to seed the rolling window for chaining
        orderedScores: p.orderedScores || [],
      });
    }
  });
  ppPlayerList.sort(function(a,b){ return b.cost - a.cost; });

  // ── Search ─────────────────────────────────────────────────────────────
  window.ppSearch = function() {
    var inp  = document.getElementById('pp-search-input');
    var drop = document.getElementById('pp-drop');
    var q    = inp.value.trim().toLowerCase();
    if (!q) { drop.classList.remove('open'); return; }
    var matches = ppPlayerList.filter(function(p){
      return p.name.toLowerCase().indexOf(q) >= 0;
    }).slice(0, 12);
    if (!matches.length) { drop.classList.remove('open'); return; }
    drop.innerHTML = matches.map(function(p){
      var beStr = p.breakEven != null ? 'BE ' + p.breakEven : '';
      return '<div class="pp-di" onclick="ppSelectPlayer(\'' + p.pid + '\')">'
           + '<div class="pp-di-name">' + esc(p.name) + '</div>'
           + '<div class="pp-di-meta">' + fmt$(p.cost)
           + (beStr ? ' · ' + beStr : '')
           + ' · ' + p.gamesPlayed + ' game' + (p.gamesPlayed===1?'':'s')
           + '</div></div>';
    }).join('');
    drop.classList.add('open');
  };

  document.addEventListener('click', function(e){
    var wrap = document.getElementById('pp-search-wrap');
    if (wrap && !wrap.contains(e.target))
      document.getElementById('pp-drop').classList.remove('open');
  });

  // ── Select player ──────────────────────────────────────────────────────
  window.ppSelectPlayer = function(pid) {
    ppSelectedPid = pid;
    var p = ppPlayerList.find(function(x){ return x.pid === pid; });
    if (!p) return;

    document.getElementById('pp-drop').classList.remove('open');
    document.getElementById('pp-search-input').value = p.name;
    document.getElementById('pp-no-player').style.display  = 'none';
    document.getElementById('pp-player-card').style.display = '';

    document.getElementById('pp-pname').textContent = p.name;
    document.getElementById('pp-pmeta').textContent =
      p.gamesPlayed + ' game' + (p.gamesPlayed===1?'':'s') + ' played';

    // Score history tiles
    var scoreKeys = Object.keys(p.scores).map(Number).sort(function(a,b){return a-b;});
    var scoreHistHtml = scoreKeys.map(function(k){
      return '<span style="font-size:.75rem;color:var(--muted)">R'+k+'</span><strong>'+p.scores[String(k)]+'</strong>';
    }).join(' &nbsp; ') || '<span style="color:var(--muted)">No scores yet</span>';

    var beLabel = p.breakEven != null ? p.breakEven : '—';
    var beColor = p.breakEven != null ? (p.breakEven < 0 ? 'var(--green)' : 'var(--text)') : 'var(--muted)';

    document.getElementById('pp-pstats').innerHTML = [
      '<div class="pp-stat"><div class="pp-stat-label">Current Price</div><div class="pp-stat-val">' + fmt$(p.cost) + '</div></div>',
      '<div class="pp-stat"><div class="pp-stat-label">Start Price</div><div class="pp-stat-val">' + fmt$(p.startPrice) + '</div></div>',
      '<div class="pp-stat"><div class="pp-stat-label">R' + (CUR_ROUND+1) + ' Break-Even</div><div class="pp-stat-val" style="color:' + beColor + '">' + beLabel + '</div></div>',
      '<div class="pp-stat" style="flex:2;min-width:200px"><div class="pp-stat-label">Score History</div>'
        + '<div style="display:flex;gap:.5rem;align-items:baseline;flex-wrap:wrap;margin-top:.15rem;font-size:.9rem">' + scoreHistHtml + '</div></div>',
    ].join('');

    // Build round input boxes (3 rounds: R+1, R+2, R+3)
    var inputsEl = document.getElementById('pp-round-inputs');
    inputsEl.innerHTML = '';
    for (var i = 0; i < 3; i++) {
      var rNum = CUR_ROUND + 1 + i;
      var div  = document.createElement('div');
      div.className = 'pp-round-input';
      div.id = 'pp-ri-' + i;
      div.innerHTML =
        '<div class="pp-round-label">Round ' + rNum + '</div>'
        + '<div class="pp-round-be" id="pp-rbe-' + i + '"><span style="color:var(--muted)">BE: —</span></div>'
        + '<input type="number" id="pp-rscore-' + i + '" min="0" max="250" placeholder="Score…"'
        + ' oninput="ppRecalc()" onchange="ppRecalc()">';
      inputsEl.appendChild(div);
    }

    ppRecalc();
  };

  // ── Recalculate projections ────────────────────────────────────────────
  window.ppRecalc = function() {
    if (!ppSelectedPid) return;
    var p = ppPlayerList.find(function(x){ return x.pid === ppSelectedPid; });
    if (!p) return;

    var tbody       = document.getElementById('pp-results-body');
    var basePrice   = p.cost;
    var rows        = '';
    var hasInput    = false;

    // Rolling window state — seeded from the player's known scores (oldest-first).
    // The window holds up to the last 4 scores (the 5th slot = upcoming score).
    var window5 = p.orderedScores.slice();  // grows as we project forward
    var runPrice = p.cost;                  // rounded display price
    var gamesInWindow = p.gamesPlayed;

    for (var i = 0; i < 3; i++) {
      var rNum   = CUR_ROUND + 1 + i;
      var inpEl  = document.getElementById('pp-rscore-' + i);
      var rawVal = inpEl ? inpEl.value.trim() : '';
      var score  = rawVal !== '' ? parseInt(rawVal, 10) : null;

      // BE for this round:
      // Round 0 (R+1) → always use the API-sourced breakEven (exact).
      // Round 1+ (R+2, R+3) → chain from rolling window.
      var be = (i === 0 && p.breakEven != null)
               ? p.breakEven
               : chainBE(runPrice, window5);

      // Update the BE display in the input box
      var beEl = document.getElementById('pp-rbe-' + i);
      if (beEl) {
        if (be != null) {
          var beClr = score != null
            ? (score >= be ? 'style="color:var(--green)"' : 'style="color:var(--red)"')
            : '';
          beEl.innerHTML = 'BE: <strong ' + beClr + '>' + be + '</strong>';
        } else {
          beEl.innerHTML = '<span style="color:var(--muted)">BE: —</span>';
        }
      }

      if (score === null || isNaN(score)) {
        rows += '<tr><td style="color:var(--muted)">R' + rNum + '</td>'
              + '<td colspan="6" style="color:var(--muted);font-style:italic">Enter score above</td></tr>';
        break;
      }

      hasInput = true;

      var vsBE  = be != null ? score - be : null;
      var vsBEHtml = vsBE != null
        ? (vsBE >= 0 ? '<span class="pp-gain">+'+vsBE+' 🟢</span>'
                     : '<span class="pp-loss">'+vsBE+' 🔴</span>')
        : '—';

      var projPrice   = projectPrice(runPrice, score, be);
      var roundChange = projPrice - runPrice;
      var totalChange = projPrice - basePrice;

      var chgHtml = function(v) {
        return v === 0 ? '<span class="pp-neutral">—</span>'
             : v  > 0 ? '<span class="pp-gain">▲ '+fmt$(v)+'</span>'
                      : '<span class="pp-loss">▼ '+fmt$(Math.abs(v))+'</span>';
      };
      var totHtml = function(v) {
        return v === 0 ? '<span class="pp-neutral">—</span>'
             : v  > 0 ? '<span class="pp-gain">+'+fmt$(v)+'</span>'
                      : '<span class="pp-loss">-'+fmt$(Math.abs(v))+'</span>';
      };

      var rowCls = (vsBE != null && vsBE >= 0) ? 'pp-be-hit' : (vsBE != null ? 'pp-be-miss' : '');
      rows += '<tr class="' + rowCls + '">'
        + '<td><strong>R'+rNum+'</strong></td>'
        + '<td><strong>'+score+'</strong></td>'
        + '<td>'+(be != null ? be : '—')+'</td>'
        + '<td>'+vsBEHtml+'</td>'
        + '<td><strong>'+fmt$(projPrice)+'</strong></td>'
        + '<td>'+chgHtml(roundChange)+'</td>'
        + '<td>'+totHtml(totalChange)+'</td>'
        + '</tr>';

      // ── Advance the rolling window ────────────────────────────────
      // Push this projected score into the window (oldest-first).
      // Cap window at last 4 entries (the 5th slot = next upcoming score).
      window5.push(score);
      if (window5.length > 4) window5 = window5.slice(window5.length - 4);
      gamesInWindow += 1;
      runPrice = projPrice;
    }

    tbody.innerHTML = hasInput
      ? rows
      : '<tr><td colspan="7" class="pp-empty">Enter projected scores above to see price projections</td></tr>';
  };

  // ── Clear ──────────────────────────────────────────────────────────────
  window.ppClear = function() {
    ppSelectedPid = null;
    document.getElementById('pp-search-input').value = '';
    document.getElementById('pp-player-card').style.display  = 'none';
    document.getElementById('pp-no-player').style.display    = '';
    document.getElementById('pp-drop').classList.remove('open');
  };

}

// ── STATS INIT ───────────────────────────────────────────────────────────────
// Requires PLAYERS to be populated by _initApp first.
function _initStats() {

  // ── Feature flag — show/hide coming-soon vs live content ─────────────────
  document.getElementById('stats-coming-soon').style.display = ENABLE_STATS ? 'none' : '';
  document.getElementById('stats-content').style.display     = ENABLE_STATS ? ''      : 'none';
  if (!ENABLE_STATS) return;

  // ── Defaults from meta (or hardcoded fallback) ────────────────────────────
  var META_DEFAULTS = (window._INLINE_DATA && window._INLINE_DATA.meta && window._INLINE_DATA.meta.statsDefaults)
    ? window._INLINE_DATA.meta.statsDefaults
    : {minMinutes: 60, minGames: 2};

  // ── Stat metadata ─────────────────────────────────────────────────────────
  var STAT_META = {
    TOG:  {label:'Minutes',         pts:null,    floor:false, isNegative:false},
    TCK:  {label:'Tackles',         pts:1,       floor:false, isNegative:false},
    TB:   {label:'Tackle Breaks',   pts:2,       floor:false, isNegative:false},
    MT:   {label:'Missed Tackles',  pts:-2,      floor:false, isNegative:true},
    MG:   {label:'Run Metres',      pts:0.1,     floor:true,  isNegative:false},
    KM:   {label:'Kick Metres',     pts:0.03333, floor:true,  isNegative:false},
    KD:   {label:'Kicks Defused',   pts:1,       floor:false, isNegative:false},
    T:    {label:'Tries',           pts:8,       floor:false, isNegative:false},
    TS:   {label:'Try Saves',       pts:5,       floor:false, isNegative:false},
    TA:   {label:'Try Assists',     pts:5,       floor:false, isNegative:false},
    G:    {label:'Goals',           pts:2,       floor:false, isNegative:false},
    FG:   {label:'Field Goals',     pts:5,       floor:false, isNegative:false},
    LB:   {label:'Line Breaks',     pts:4,       floor:false, isNegative:false},
    LBA:  {label:'LB Assists',      pts:2,       floor:false, isNegative:false},
    FDO:  {label:'Forced Drop-Outs', pts:2,       floor:false, isNegative:false},
    OFH:  {label:'Offloads',        pts:4,       floor:false, isNegative:false},
    OFG:  {label:'Offloads (Gnd)',  pts:2,       floor:false, isNegative:false},
    TO:   {label:'Turnovers',       pts:4,       floor:false, isNegative:false},
    ER:   {label:'Errors',          pts:-2,      floor:false, isNegative:true},
    SAI:  {label:'6-Again Inf.',    pts:-1,      floor:false, isNegative:true},
    PC:   {label:'Penalties',       pts:-2,      floor:false, isNegative:true},
    EFIG: {label:'Escape in Goal',  pts:2,       floor:false, isNegative:false},
    FTF:  {label:'40/20',           pts:4,       floor:false, isNegative:false},
    SB:   {label:'Sin Bin',         pts:-5,      floor:false, isNegative:true},
    SO:   {label:'Send Off',        pts:-10,     floor:false, isNegative:true},
  };

  var POS_LABELS = {1:'HOK', 2:'FRF', 3:'2RF', 4:'HLF', 5:'CTW', 6:'HFB'};

  function formatPositions(positions) {
    if (!positions || !positions.length) return '';
    return positions.map(function(p){ return POS_LABELS[p] || (''+p); }).join(' / ');
  }

  // Stat groups
  var CORE_GROUPS = [
    {name:'Base',      keys:['TOG','TCK','MG','TB','MT']},
    {name:'Attack',    keys:['T','TA','LB','LBA','OFH','FDO']},
    {name:'Kicking',   keys:['KM','G','KD','FTF','FG']},
  ];
  var ALL_GROUPS = [
    {name:'Base',      keys:['TOG','TCK','MG','TB','MT']},
    {name:'Attack',    keys:['T','TA','LB','LBA','OFH','FDO','TS','TO']},
    {name:'Kicking',   keys:['KM','G','KD','FTF','FG']},
    {name:'Negative',  keys:['ER','PC','SAI','SB','SO']},
  ];
  var LB_STATS = ['TCK','TB','MT','MG','KM','T','TS','TA','G','LB','LBA','FDO','OFH','TO','ER','SAI','PC','FG','FTF','KD','EFIG','SB','SO'];

  // ── Helpers ───────────────────────────────────────────────────────────────
  function calcPts(key, rawVal) {
    var m = STAT_META[key];
    if (!m || m.pts === null) return null;
    return m.floor ? Math.floor(rawVal * m.pts) : rawVal * m.pts;
  }
  function fmtPts(v) {
    if (v === 0) return '0';
    return (v > 0 ? '+' : '') + v.toFixed(v % 1 === 0 ? 0 : 1);
  }
  function fmtRaw(key, v) {
    if (key === 'KM' || key === 'MG') return Math.round(v).toString();
    if (key === 'TOG') return Math.round(v).toString();
    return v % 1 < 0.05 ? Math.round(v).toString() : v.toFixed(1);
  }
  function ordinal(n) {
    var s = ['th','st','nd','rd'], v = n % 100;
    return n + (s[(v - 20) % 10] || s[v] || s[0]);
  }
  function rankColour(rank, total) {
    if (!rank || !total || total < 2) return 'var(--muted)';
    var pct = (rank - 1) / (total - 1);
    if (pct <= 0.2)  return 'var(--green)';
    if (pct <= 0.45) return '#86efac';
    if (pct <= 0.55) return 'var(--accent)';
    if (pct <= 0.75) return '#fb923c';
    return 'var(--red)';
  }

  // ── Build player list ─────────────────────────────────────────────────────
  var STAT_PLAYERS = [];
  Object.keys(PLAYERS).forEach(function(pid) {
    var p = PLAYERS[pid];
    if (!p || !p.name) return;
    var hs = p.historicalStats || {};
    if (!Object.keys(hs).length) return;
    STAT_PLAYERS.push({pid:pid, name:p.name, cost:p.cost||p.currentPrice||0, rounds:hs, positions:p.positions||[]});
  });
  STAT_PLAYERS.sort(function(a,b){return b.cost - a.cost;});

  // ── Core filtered avg function ────────────────────────────────────────────
  // Returns {avg, games} or null if no qualifying rounds
  function playerAvg(sp, key, togMin) {
    var qual = Object.keys(sp.rounds).filter(function(r){ return (sp.rounds[r].TOG||0) >= togMin; });
    if (!qual.length) return null;
    var sum = qual.reduce(function(s,r){ return s+(sp.rounds[r][key]||0); }, 0);
    return {avg: sum/qual.length, games: qual.length};
  }

  // ── Rank within a position pool ───────────────────────────────────────────
  function playerRankInPos(pid, key, togMin, posFilter) {
    var m = STAT_META[key];
    if (!m || m.pts === null) return null;
    var target = null;
    var all = [];
    STAT_PLAYERS.forEach(function(sp) {
      if (posFilter && posFilter > 0 && (!sp.positions || sp.positions.indexOf(posFilter) < 0)) return;
      var r = playerAvg(sp, key, togMin);
      if (!r) return;
      all.push({pid:sp.pid, avg:r.avg});
      if (sp.pid === pid) target = r.avg;
    });
    if (target === null || !all.length) return null;
    var desc = !m.isNegative;
    all.sort(function(a,b){ return desc ? b.avg - a.avg : a.avg - b.avg; });
    for (var i=0; i<all.length; i++) {
      if (all[i].pid === pid) return {rank:i+1, total:all.length};
    }
    return null;
  }

  // (legacy compat — uses all players, no pos filter)
  function playerRank(pid, key, togMin) {
    return playerRankInPos(pid, key, togMin, 0);
  }

  // ── View switching ────────────────────────────────────────────────────────
  window.statsShowView = function(view) {
    ['player','leaderboard'].forEach(function(v) {
      var el = document.getElementById('stats-view-' + v);
      if (el) el.style.display = (v === view ? '' : 'none');
      var btn = document.querySelector('.stats-pill[data-view="' + v + '"]');
      if (btn) btn.classList.toggle('active', v === view);
    });
    if (view === 'leaderboard') statsRenderLeaderboard();
  };

  // ── Stat dropdown ─────────────────────────────────────────────────────────
  function buildStatOptions(selId) {
    var sel = document.getElementById(selId);
    if (!sel) return;
    sel.innerHTML = '';
    LB_STATS.forEach(function(key) {
      var opt = document.createElement('option');
      opt.value = key;
      opt.textContent = STAT_META[key] ? STAT_META[key].label : key;
      sel.appendChild(opt);
    });
  }
  buildStatOptions('stats-lb-stat');

  // ── PLAYER VIEW ───────────────────────────────────────────────────────────
  var statsSelectedPid = null;
  var statsPlayerMode = 'core';

  // Inject position selector into player view sticky bar
  (function() {
    var wrap = document.getElementById('stats-search-wrap');
    if (!wrap) return;
    // Add TOG filter + position selector below search if not already present
    if (!document.getElementById('stats-player-filters')) {
      var filterDiv = document.createElement('div');
      filterDiv.id = 'stats-player-filters';
      filterDiv.style.cssText = 'display:flex;gap:.5rem;align-items:center;flex-wrap:wrap;padding:.5rem 0 0;font-size:.8rem;color:var(--muted);';
      filterDiv.innerHTML =
        '<span>Min min:</span>'
        + '<select id="stats-player-tog" class="stats-select" onchange="statsRefreshPlayerCard()">'
        + ['0','40','50','60','70'].map(function(v){
            return '<option value="'+v+'"'+(v===''+META_DEFAULTS.minMinutes?' selected':'')+'>'+v+(v==='0'?' (all)':'+')+'</option>';
          }).join('')
        + '</select>'
        + '<span style="margin-left:.5rem">Position:</span>'
        + '<select id="stats-player-pos" class="stats-select" onchange="statsRefreshPlayerCard()">'
        + '<option value="0">All</option>'
        + Object.keys(POS_LABELS).map(function(k){ return '<option value="'+k+'">'+POS_LABELS[k]+'</option>'; }).join('')
        + '</select>';
      wrap.parentNode.insertBefore(filterDiv, wrap.nextSibling);
    }
  })();

  window.statsSearch = function() {
    var inp  = document.getElementById('stats-search-input');
    var drop = document.getElementById('stats-drop');
    if (!inp || !drop) return;
    var q = inp.value.trim().toLowerCase();
    if (!q) { drop.classList.remove('open'); return; }
    var matches = STAT_PLAYERS.filter(function(p) {
      return p.name.toLowerCase().indexOf(q) >= 0;
    }).slice(0, 10);
    if (!matches.length) { drop.classList.remove('open'); return; }
    drop.innerHTML = '';
    matches.forEach(function(p) {
      var div = document.createElement('div');
      div.className = 'stats-drop-item';
      div.textContent = p.name;
      div.addEventListener('click', function() { window.statsSelectPlayer(p.pid); });
      drop.appendChild(div);
    });
    drop.classList.add('open');
  };

  window.statsSelectPlayer = function(pid) {
    statsSelectedPid = pid;
    var inp  = document.getElementById('stats-search-input');
    var drop = document.getElementById('stats-drop');
    var sp = STAT_PLAYERS.find(function(x){ return x.pid===pid; });
    if (!sp) return;
    if (inp) inp.value = sp.name;
    if (drop) drop.classList.remove('open');
    // Auto-set position to player's primary position
    var posSel = document.getElementById('stats-player-pos');
    if (posSel && sp.positions && sp.positions.length) {
      posSel.value = sp.positions[0];
    }
    statsRenderPlayerCard(pid);
  };

  function getPlayerTogFilter() {
    var sel = document.getElementById('stats-player-tog');
    return sel ? parseInt(sel.value, 10) : META_DEFAULTS.minMinutes;
  }
  function getPlayerPosFilter() {
    var sel = document.getElementById('stats-player-pos');
    return sel ? parseInt(sel.value, 10) : 0;
  }

  window.statsRefreshPlayerCard = function() {
    if (statsSelectedPid) statsRenderPlayerCard(statsSelectedPid);
  };

  window.statsSetPlayerMode = function(mode) {
    statsPlayerMode = mode;
    document.querySelectorAll('.stats-mode-btn').forEach(function(btn) {
      btn.classList.toggle('active', btn.getAttribute('data-mode') === mode);
    });
    if (statsSelectedPid) statsRenderPlayerCard(statsSelectedPid);
  };

  function statsRenderPlayerCard(pid) {
    var sp = STAT_PLAYERS.find(function(x){ return x.pid===pid; });
    var noEl   = document.getElementById('stats-no-player');
    var cardEl = document.getElementById('stats-player-card');
    if (!sp) { if(noEl) noEl.style.display=''; if(cardEl) cardEl.style.display='none'; return; }
    if (noEl) noEl.style.display='none';
    if (cardEl) cardEl.style.display='';

    var togMin = getPlayerTogFilter();
    var posFilter = getPlayerPosFilter();
    var allRounds = Object.keys(sp.rounds).sort(function(a,b){ return parseInt(a)-parseInt(b); });
    var qualRounds = allRounds.filter(function(r){ return (sp.rounds[r].TOG||0) >= togMin; });

    var price = sp.cost ? ('$'+(sp.cost/1000).toFixed(0)+'k') : '';
    var posTags = formatPositions(sp.positions);
    var posLabel = posFilter > 0 ? (POS_LABELS[posFilter] || posFilter) : 'All';

    // ── Summary card ──────────────────────────────────────────────────────
    var headlineKeys = ['TOG','TCK','MG','T'];
    var headlineHtml = headlineKeys.map(function(key) {
      var r = playerAvg(sp, key, togMin);
      if (!r) return '';
      return '<div class="stats-cell" style="flex:1;min-width:60px">'
        + '<div class="stats-cell-label">'+esc(STAT_META[key].label)+'</div>'
        + '<div class="stats-cell-val">'+fmtRaw(key, r.avg)+'</div>'
        + '</div>';
    }).join('');

    var summaryHtml = '<div class="stats-card" style="padding:.75rem;margin-bottom:.75rem;background:var(--card);border-radius:var(--radius);border:1px solid var(--border);">'
      + '<div class="stats-player-name">'+esc(sp.name)+(posTags ? ' <span class="stats-pos-tags">'+esc(posTags)+'</span>' : '')+'</div>'
      + '<div class="stats-player-meta" style="margin:.25rem 0 .5rem;">'+(price?price+' · ':'')+qualRounds.length+' qualified game'+(qualRounds.length!==1?'s':'')+' (TOG ≥'+togMin+' min)</div>'
      + '<div style="display:flex;flex-wrap:wrap;gap:.5rem;">'+headlineHtml+'</div>'
      + '</div>';

    // Mode toggle
    var modeHtml = '<div class="stats-mode-pills" style="margin-bottom:.75rem;">'
      + '<button class="stats-mode-btn'+(statsPlayerMode==='core'?' active':'')+'\" data-mode="core" onclick="statsSetPlayerMode(\'core\')">Core Stats</button>'
      + '<button class="stats-mode-btn'+(statsPlayerMode==='all'?' active':'')+'\" data-mode="all" onclick="statsSetPlayerMode(\'all\')">All Stats</button>'
      + '</div>';

    if (!qualRounds.length) {
      cardEl.innerHTML = summaryHtml + modeHtml
        + '<div class="stats-empty">No qualifying rounds with the selected minutes filter.</div>'
        + renderGameHistory(sp, allRounds, togMin);
      return;
    }

    // ── Grouped stat sections ─────────────────────────────────────────────
    var groups = statsPlayerMode === 'core' ? CORE_GROUPS : ALL_GROUPS;
    var groupsHtml = groups.map(function(grp) {
      var cells = grp.keys.map(function(key) {
        var r = playerAvg(sp, key, togMin);
        if (!r) return '';
        var raw = r.avg;
        var label = STAT_META[key] ? STAT_META[key].label : key;
        var pts = calcPts(key, raw);
        var rankInfo = playerRankInPos(pid, key, togMin, posFilter);
        var rankN = rankInfo ? rankInfo.rank : null;
        var rankTotal = rankInfo ? rankInfo.total : null;

        var secondary = '';
        var ptsPart = (pts !== null && Math.abs(pts) >= 0.05) ? ('\u2248 '+fmtPts(pts)+' pts') : '';
        var rankPart = '';
        if (rankN !== null && rankN <= 999) {
          var col = rankColour(rankN, rankTotal);
          rankPart = '<span style="color:'+col+';font-weight:700;">'+ordinal(rankN)+'</span>'
            + (posFilter>0 ? '<span style="color:var(--muted);font-size:.7em"> '+esc(posLabel)+'</span>' : '');
        }
        if (ptsPart || rankPart) {
          var sep = (ptsPart && rankPart) ? ' <span style="color:var(--border)">\xb7</span> ' : '';
          secondary = '<div class="stats-cell-pts">'+(ptsPart?esc(ptsPart):'')+sep+rankPart+'</div>';
        }

        return '<div class="stats-cell">'
          + '<div class="stats-cell-label">'+esc(label)+'</div>'
          + '<div class="stats-cell-val">'+fmtRaw(key, raw)+'</div>'
          + secondary
          + '</div>';
      }).join('');

      return '<div class="stat-group" style="margin-bottom:.75rem;">'
        + '<div class="stats-group-label">'+esc(grp.name)+'</div>'
        + '<div class="stats-grid stats-grid-3">'+cells+'</div>'
        + '</div>';
    }).join('');

    // ── Game history ──────────────────────────────────────────────────────
    var historyHtml = renderGameHistory(sp, allRounds, togMin);

    cardEl.innerHTML = summaryHtml + modeHtml + groupsHtml + historyHtml;
  }

  function renderGameHistory(sp, allRounds, togMin) {
    if (!allRounds.length) return '';
    var histKeys = ['TOG','TCK','MG','T','LB'];
    var headerCells = '<th style="text-align:left;padding:.3rem .5rem;font-size:.75rem;color:var(--muted);">Rnd</th>'
      + histKeys.map(function(k){ return '<th style="text-align:right;padding:.3rem .5rem;font-size:.75rem;color:var(--muted);">'+esc(STAT_META[k]?STAT_META[k].label:k)+'</th>'; }).join('');
    var rows = allRounds.map(function(r) {
      var rd = sp.rounds[r];
      var tog = rd.TOG || 0;
      var isLow = tog < togMin;
      var rowClass = isLow ? ' class="low-minutes"' : '';
      var rowStyle = isLow ? ' style="opacity:.5;"' : '';
      var marker = isLow ? ' <span style="font-size:.65rem;color:var(--muted);">low</span>' : '';
      var cells = histKeys.map(function(k){ return '<td style="text-align:right;padding:.25rem .5rem;font-size:.8rem;">'+(rd[k]||0)+'</td>'; }).join('');
      return '<tr'+rowClass+rowStyle+'>'
        + '<td style="padding:.25rem .5rem;font-size:.8rem;white-space:nowrap;">R'+r+marker+'</td>'
        + cells
        + '</tr>';
    }).join('');
    return '<div style="margin-top:.75rem;">'
      + '<div class="stats-group-label">Game History</div>'
      + '<div style="overflow-x:auto;margin-top:.25rem;">'
      + '<table style="width:100%;border-collapse:collapse;"><thead><tr>'+headerCells+'</tr></thead><tbody>'+rows+'</tbody></table>'
      + '</div></div>';
  }

// Initialize the separated logic
setupFeedbackForm();
fetchLeagueData();



}

// INLINE DATA GOES HERE (Truncated in instructions, but should be pasted fully)

fetch(window.location.hostname === 'jbfa26.netlify.app'
  ? 'https://raw.githubusercontent.com/donaldpcominos-sketch/JBFA26/main/data.json'
  : 'https://raw.githubusercontent.com/donaldpcominos-sketch/JBFA26/dev/data.json')
  .then(function(r){
    if(!r.ok) throw new Error('HTTP '+r.status);
    return r.json();
  })
  .then(function(data){
    _initApp(data);
    _initPricePredictor(data.beModel || null);
  })
  .catch(function(err){
    console.warn('Remote fetch failed ('+err+'), using inline data.json');
    _initApp(_INLINE_DATA);
    _initPricePredictor((_INLINE_DATA && _INLINE_DATA.beModel) || null);
  });